import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class SQL {
    private Map<String, Table> tables;

    public SQL(String[] names, int[] columns) {
        tables = new HashMap<>();
        for (int i = 0; i < names.length; i++) {
            tables.put(names[i], new Table(columns[i]));
        }
    }

    public void insertRow(String name, String[] row) {
        tables.get(name).insertRow(row);
    }

    public void deleteRow(String name, int rowId) {
        tables.get(name).deleteRow(rowId);
    }

    public String selectCell(String name, int rowId, int columnId) {
        return tables.get(name).selectCell(rowId, columnId);
    }

    private static class Table {
        private int nextId;
        private List<Row> rows;
        private int numColumns;

        public Table(int numColumns) {
            this.numColumns = numColumns;
            this.nextId = 1;
            this.rows = new ArrayList<>();
        }

        public void insertRow(String[] row) {
            rows.add(new Row(nextId++, row));
        }

        public void deleteRow(int rowId) {
            rows.removeIf(r -> r.id == rowId);
        }

        public String selectCell(int rowId, int columnId) {
            return rows.stream().filter(r -> r.id == rowId).findFirst().get().values[columnId - 1];
        }
    }

    private static class Row {
        private int id;
        private String[] values;

        public Row(int id, String[] values) {
            this.id = id;
            this.values = values;
        }
    }
}
